/*
 * fpclassifyf() test harness — prints (input_hex, classification) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly fpclassifyf  (test_fpclassifyf_opt.elf)
 *   2. Linked with toolchain's default fpclassifyf        (test_fpclassifyf_ref.elf)
 * Run both, diff the output to find discrepancies.
 *
 * FP_ZERO=0, FP_SUBNORMAL=2, FP_NORMAL=4, FP_INFINITE=1, FP_NAN=3
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x)
{
    printf("%08lx %d\n", (unsigned long)f2u(x), fpclassify(x));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Zero values (FP_ZERO) */
static void test_zeros(void)
{
    emit(0.0f);      /* +0 */
    emit(-0.0f);     /* -0 */
}

/* 2. Denormal/Subnormal values (FP_SUBNORMAL) */
static void test_denormals(void)
{
    emit_u(0x00000001u); /* min positive denorm */
    emit_u(0x80000001u); /* min negative denorm */
    emit_u(0x00400000u); /* mid positive denorm */
    emit_u(0x80400000u); /* mid negative denorm */
    emit_u(0x007fffffu); /* max positive denorm */
    emit_u(0x807fffffu); /* max negative denorm */
}

/* 3. Normal values (FP_NORMAL) */
static void test_normal(void)
{
    /* Smallest normal values */
    emit(FLT_MIN);
    emit(-FLT_MIN);

    /* Small positive/negative */
    float vals[] = {
        0.5f, -0.5f,
        1.0f, -1.0f,
        1.5f, -1.5f,
        2.0f, -2.0f,
        10.0f, -10.0f,
        100.0f, -100.0f,
        1000.0f, -1000.0f,
        0.78539816f, -0.78539816f,
        1.57079633f, -1.57079633f,
        3.14159265f, -3.14159265f,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);

    /* Large values near max */
    emit(FLT_MAX);
    emit(-FLT_MAX);
}

/* 4. Infinity values (FP_INFINITE) */
static void test_infinities(void)
{
    emit_u(0x7f800000u);  /* +Infinity */
    emit_u(0xff800000u);  /* -Infinity */
}

/* 5. NaN values (FP_NAN) */
static void test_nans(void)
{
    /* Quiet NaN */
    emit_u(0x7fc00000u);  /* +qNaN (canonical) */
    emit_u(0xffc00000u);  /* -qNaN */

    /* Signaling NaN */
    emit_u(0x7f800001u);  /* +sNaN */
    emit_u(0xff800001u);  /* -sNaN */

    /* Other NaN patterns */
    emit_u(0x7fffffff u);  /* quiet NaN with max mantissa */
    emit_u(0xff800002u);  /* signaling with small mantissa */
}

/* 6. Powers of 2 (all FP_NORMAL) */
static void test_powers_of_2(void)
{
    for (int i = -20; i <= 20; i++) {
        float v = powf(2.0f, (float)i);
        emit(v);
        emit(-v);
    }
}

/* 7. Transition boundaries */
static void test_boundaries(void)
{
    /* Boundary: zero to denormal */
    emit_u(0x00000000u);  /* +0 (FP_ZERO) */
    emit_u(0x00000001u);  /* first denormal (FP_SUBNORMAL) */

    /* Boundary: denormal to normal */
    emit_u(0x007fffffu);  /* max denormal (FP_SUBNORMAL) */
    emit_u(0x00800000u);  /* min normal (FP_NORMAL) */

    /* Boundary: normal to infinity */
    emit_u(0x7f7fffffu);  /* max normal (FP_NORMAL) */
    emit_u(0x7f800000u);  /* +Infinity (FP_INFINITE) */

    /* Negative boundaries */
    emit_u(0x80000000u);  /* -0 (FP_ZERO) */
    emit_u(0x80000001u);  /* first negative denormal (FP_SUBNORMAL) */
    emit_u(0x807fffffu);  /* max negative denormal (FP_SUBNORMAL) */
    emit_u(0x80800000u);  /* min negative normal (FP_NORMAL) */
    emit_u(0xff7fffffu);  /* max negative normal (FP_NORMAL) */
    emit_u(0xff800000u);  /* -Infinity (FP_INFINITE) */
}

/* 8. Sample across all categories */
static void test_comprehensive(void)
{
    float test_vals[] = {
        /* FP_ZERO */
        0.0f, -0.0f,
        /* FP_SUBNORMAL (sampled denormals) */
        1.0e-40f, -1.0e-40f,
        /* FP_NORMAL */
        0.5f, -0.5f, 1.0f, -1.0f, 2.0f, -2.0f, 100.0f, -100.0f,
        /* FP_INFINITE */
        INFINITY, -INFINITY,
        /* FP_NAN */
        NAN,
    };
    int n = sizeof(test_vals) / sizeof(test_vals[0]);
    for (int i = 0; i < n; i++)
        emit(test_vals[i]);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_zeros();
    test_denormals();
    test_normal();
    test_infinities();
    test_nans();
    test_powers_of_2();
    test_boundaries();
    test_comprehensive();
    return 0;
}

