/*
 * atan2f() test harness — prints (y_hex, x_hex, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly atan2f  (test_atan2f_opt.elf)
 *   2. Linked with toolchain's default atan2f        (test_atan2f_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float y, float x)
{
    float r = atan2f(y, x);
    printf("%08lx %08lx %08lx\n", (unsigned long)f2u(y), (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t y_bits, uint32_t x_bits)
{
    emit(u2f(y_bits), u2f(x_bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zero cases */
    emit(0.0f, 1.0f);
    emit(-0.0f, 1.0f);
    emit(1.0f, 0.0f);
    emit(1.0f, -0.0f);
    emit(0.0f, 0.0f);
    emit(-0.0f, -0.0f);

    /* With infinity */
    emit_u(0x7f800000u, 0x7f800000u);  /* +Inf, +Inf */
    emit_u(0x7f800000u, 0xff800000u);  /* +Inf, -Inf */
    emit_u(0xff800000u, 0x7f800000u);  /* -Inf, +Inf */
    emit_u(0xff800000u, 0xff800000u);  /* -Inf, -Inf */
    emit(1.0f, INFINITY);
    emit(1.0f, -INFINITY);
    emit(INFINITY, 1.0f);
    emit(-INFINITY, 1.0f);

    /* With NaN */
    emit_u(0x7fc00000u, 0x3f800000u);  /* qNaN, 1.0 */
    emit_u(0x3f800000u, 0x7fc00000u);  /* 1.0, qNaN */
    emit_u(0x7fc00000u, 0x7fc00000u);  /* qNaN, qNaN */
}

/* 2. Tiny values */
static void test_tiny(void)
{
    emit_u(0x00000001u, 0x3f800000u);  /* denorm, 1.0 */
    emit_u(0x3f800000u, 0x00000001u);  /* 1.0, denorm */
    emit_u(0x80000001u, 0x3f800000u);  /* -denorm, 1.0 */
    emit(1.0e-20f, 1.0f);
    emit(1.0f, 1.0e-20f);
    emit(1.0e-10f, 1.0e-10f);
    emit(-1.0e-20f, 1.0f);
    emit(1.0f, -1.0e-20f);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    float pi   = 3.14159265358979323846f;
    float pi_2 = 1.57079632679489661923f;
    float pi_4 = 0.78539816339744830962f;

    emit(pi_4, 1.0f);    /* atan(1) */
    emit(1.0f, pi_4);
    emit(pi_2, pi_2);
    emit(pi_4, -pi_4);   /* atan(-1) = -pi/4 */
    emit(-pi_4, pi_4);
    emit(pi, pi);
    emit(-pi, -pi);
}

/* 4. Large arguments */
static void test_large(void)
{
    float vals[] = {
        1e10f, 1e20f, FLT_MAX,
        -1e10f, -1e20f, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            emit(vals[i], vals[j]);
        }
    }
}

/* 5. Quadrant boundaries */
static void test_quadrant(void)
{
    float offsets[] = { -1e-5f, 0.0f, 1e-5f };
    int noff = sizeof(offsets) / sizeof(offsets[0]);

    /* Quadrant boundaries: y-axis and x-axis crossings */
    float y_vals[] = { 0.0f, -0.0f, 1.0f, -1.0f };
    float x_vals[] = { 0.0f, -0.0f, 1.0f, -1.0f };

    for (int i = 0; i < 4; i++) {
        for (int j = 0; j < 4; j++) {
            for (int k = 0; k < noff; k++) {
                emit(y_vals[i] + offsets[k], x_vals[j]);
            }
        }
    }
}

/* 6. Hard cases near quadrant transitions */
static void test_hard(void)
{
    float pi_4 = 0.78539816339744830962f;
    float cases_y[] = {
        u2f(0x3f800000u), u2f(0xbf800000u),  /* ±1.0 */
        u2f(0x3f490fdbu), u2f(0xbf490fdbu),  /* ±pi/4 */
    };
    float cases_x[] = {
        u2f(0x3f800000u), u2f(0xbf800000u),  /* ±1.0 */
        u2f(0x3f490fdbu), u2f(0xbf490fdbu),  /* ±pi/4 */
    };
    int n_y = sizeof(cases_y) / sizeof(cases_y[0]);
    int n_x = sizeof(cases_x) / sizeof(cases_x[0]);

    for (int i = 0; i < n_y; i++) {
        for (int j = 0; j < n_x; j++) {
            emit(cases_y[i], cases_x[j]);
        }
    }
}

/* 7. Sweep all four quadrants */
static void test_sweep(void)
{
    int nsteps = 50;
    float vals[] = { 0.1f, 0.5f, 1.0f, 2.0f, 10.0f };
    for (int i = 0; i < 5; i++) {
        for (int j = 0; j < 5; j++) {
            emit(vals[i], vals[j]);
            emit(-vals[i], vals[j]);
            emit(vals[i], -vals[j]);
            emit(-vals[i], -vals[j]);
        }
    }
}

/* 8. Ratio sweep: exhaustive combinations of magnitudes */
static void test_exhaustive_small(void)
{
    float ratios[] = {
        0.01f, 0.1f, 0.5f, 1.0f, 2.0f, 10.0f, 100.0f
    };
    int n = sizeof(ratios) / sizeof(ratios[0]);

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            emit(ratios[i], ratios[j]);
            emit(-ratios[i], ratios[j]);
            emit(ratios[i], -ratios[j]);
        }
    }
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

